data.content:
Use `MockHttpMessageHandler` to control responses, and leverage `CancellationToken` for timeout/cancellation tests:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: mock handler that returns a canned response
    private static HttpClient CreateMockClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        var mock = new MockHandler(handler);
        return new HttpClient(mock);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient((req, ct) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_On500()
    {
        using var client = CreateMockClient((req, ct) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        using var client = CreateMockClient((req, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_TimesOut_WithCancellationToken()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        using var client = CreateMockClient(async (req, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow server
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal mock handler
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;
        public MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send) => _send = send;
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns:**

| Scenario | Technique |
|---|---|
| **Success/error** | Mock handler returns the desired `HttpResponseMessage` |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Timeout** | Create `CancellationTokenSource(TimeSpan)`, mock a slow `Task.Delay` |
| **Always** | Pass `CancellationToken` through to `SendAsync` so the mock can observe it |

Avoid `Thread.Sleep` in async tests — use `Task.Delay` with the token so cancellation is instant. The custom `MockHandler` avoids any external mocking dependency while giving full control over `HttpClient` behavior.
